import React from "react";
import { Link } from "react-router-dom";
import { ArrowUpRight, Sparkles } from "lucide-react";
import RatingBadge from "./rating-badages";
import "./Hero.css";

const Hero = () => {
  return (
    <div className="hero-container">
      {/* Background Video */}
      <video autoPlay loop muted playsInline className="hero-video">
        <source src="/assets/videos/background.mp4" type="video/mp4" />
        Your browser does not support the video tag.
      </video>

      <div className="hero-content">
        <div className="hero-grid">
          {/* Left Section */}
          <div className="hero-text">
            <h1 className="hero-title">
              Building
              <br />
              Digital Experiences
              <br />
              <span className="highlight">with Purpose</span>
              <br />
            </h1>
            <div className="hero-details">
              <p className="hero-description">Explore My Journey in Design and Development</p>
              <RatingBadge />
            </div>
          </div>

          {/* Right Section */}
          <div className="hero-image-container">
            <img src="/assets/images/heroimg.png" alt="Professional portrait" className="hero-image" />
          </div>
        </div>

        {/* CTA Section */}
        <div className="cta-box">
          <div className="cta-header">
            <ArrowUpRight className="cta-icon" />
            <p className="cta-text">A modern agency with new solutions for creating websites.</p>
          </div>
          <Link to="/contact" className="cta-button">
            <Sparkles className="cta-sparkle" />
            <span>Contact Me!</span>
          </Link>
        </div>
      </div>
    </div>
  );
};

export default Hero;
